VALUES
  ('social-worker-moex-02481', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'essay', '倫理是一種道德標準，用來保證專業工作者提供夠水準的服務，並且尊重個案的權
利。許多倫理守則強調六個基本倫理原則，包括自主性、有益性、無傷害性、公正、
忠誠，與真實等原則的重要性。試針對前述每一個倫理原則詳細說明其意涵，並請
各列舉一個與社會工作相關的實例解說之。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "d9e660d04e95", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02482', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'essay', '有關失智老人的照顧工作，除了醫療照顧費用對社會而言是一項沉重的負擔之外，
家庭成員所承擔的精神壓力和體力勞累更是難以估計。請說明失智老人的家庭照顧
者所面臨的困境為何？並請針對失智老人照顧政策與相關的實務工作提出檢討與
建議。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "d9e660d04e95", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02483', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列關於臺灣社會工作的歷史發展，那一個敘述錯誤？', '["1970年代初期仍有社會工作黨政化的情形", "最早的社會工作人員受聘於醫院", "臺灣的社會工作教育始於1950年代", "最早頒訂的社會保險立法是「公務人員保險法」"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "d9e660d04e95", "answer_pdf_sha1": "94a7e373f9b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02484', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列關於老人福利法的敘述，何者錯誤？', '["未領有生活津貼，且其失能程度經評估為重度以上，實際由家人照顧者，照顧者得申請發給特別照顧 津貼", "老人福利機構分為長期照顧機構、安養機構及其他老人福利機構", "中低收入老人未接受收容安置者，得申請發給生活津貼", "因精神障礙或其他心智缺陷，致不能為意思表示或受意思表示，或不能辨識其意思表示之效果之老人， 法院得因主管機關之聲請，為監護或輔助之宣告"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "d9e660d04e95", "answer_pdf_sha1": "94a7e373f9b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02485', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '老人福利法中，為了提高家庭照顧老人之意願及能力，提升老人在社區生活之自主性，政府應自行或結 合民間資源提供之社區式服務，不包含下列那一項？', '["自立生活支持服務", "教育服務", "退休準備服務", "餐飲服務"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "d9e660d04e95", "answer_pdf_sha1": "94a7e373f9b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02486', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列關於老人福利法的敘述，何者錯誤？', '["立法宗旨目標是維護老人之權益，保障其平等參與社會、政治、經濟、文化等之機會", "勞工主管機構負責主管老人就業免於歧視及支援員工照顧老人家屬與照顧服務員技能檢定之規劃、推 動及監督等事項", "各級政府老人福利之經費來源包括按年編列之老人福利預算、社會福利基金、私人或團體捐贈及其他 收入", "提供原住民老人服務及照顧者，應優先遴用原住民或熟諳原住民文化之人"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "d9e660d04e95", "answer_pdf_sha1": "94a7e373f9b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02487', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '身心障礙者權益保障法中，提供身心障礙者獲得所需之個人支持及照顧，促進其生活品質、社會參與及 自立生活的服務，不包含下列那一項？', '["社區居住", "婚姻及生育輔導", "課後照顧", "緊急救援服務"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "d9e660d04e95", "answer_pdf_sha1": "94a7e373f9b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02488', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列何者不是我國長期照顧十年計畫的服務對象？', '["65歲老人", "50歲的山地原住民", "55歲的身心障礙者", "僅IADLs（工具性日常生活活動功能）失能且獨居之老人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "d9e660d04e95", "answer_pdf_sha1": "94a7e373f9b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02489', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列關於身心障礙者個人照顧服務的敘述，何者錯誤？', '["友善服務提供到宅關懷，並支持身心障礙者社會參與", "居家復健是由物理治療師、職能治療師或語言治療師對居家需繼續復健之身心障礙者，於其居住處提 供復健治療服務", "生活重建是指由身心障礙同儕，提供心理支持，以重新建構其獨立生活能力，協助其重建生活", "社區居住是以一般社區住宅房舍提供身心障礙者非機構式之居住服務"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "d9e660d04e95", "answer_pdf_sha1": "94a7e373f9b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02490', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列關於兒童及少年福利與權益保障法的敘述，何者錯誤？', '["胎兒（包含死產）出生後7日內，接生人應將其出生之相關資料通報衛生主管機關備查", "出養應以國內收養人優先收養為原則", "政府應建立發展遲緩兒童早期通報系統，並提供早期療育服務", "國內大眾交通運輸、文教設施、康樂場所應提供身高100公分以下兒童優惠措施"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "d9e660d04e95", "answer_pdf_sha1": "94a7e373f9b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
